17	const BASE_PREMIUMS: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	  moonstone: 25,
24	};
25	
26	const PROCESSING_FEE_G = 5;
27	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1; // 10% surcharge on policy base
28	const COMPONENT_BLOCK_SIZE = 3;
29	const COMPONENT_BLOCK_PRICE_G = 60;
30	const CURSE_SURCHARGE_RATE = 0.5; // 50% of cursed item's base premium
31	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3; // 30% of enchanted item's base premium
32	const HIGH_ENCHANTMENT_THRESHOLD = 5;
33	
34	const COMPONENT_TYPES = ["rune", "moonstone"];
35	
36	const priceForComponentGroup = (count: number, unitPrice: number): number =>
37	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PRICE_G : count * unitPrice;
38	
39	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
40	
41	const isCursed = (item: Item): boolean => item.cursed === true;
42	const isHighlyEnchanted = (item: Item): boolean =>
43	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
44	
45	const surchargeFor = (items: Item[], predicate: (i: Item) => boolean, rate: number): number =>
46	  items.filter(predicate).reduce((sum, item) => sum + BASE_PREMIUMS[item.type] * rate, 0);
47	
48	const LOYALTY_YEARS_THRESHOLD = 2;
49	const LOYALTY_DISCOUNT_RATE = 0.2; // 20% discount on policy base
50	
51	const quotePremium = (items: Item[], yearsWithMHPCO: number): number => {
52	  const componentBase = COMPONENT_TYPES.reduce((sum, type) => {
53	    const count = items.filter((i) => i.type === type).length;
54	    return sum + priceForComponentGroup(count, BASE_PREMIUMS[type]);
55	  }, 0);
56	  const otherItemsBase = items
57	    .filter((i) => !isComponent(i))
58	    .reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
59	  const policyBase = otherItemsBase + componentBase;
60	  const curseSurcharge = surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
61	  const enchantmentSurcharge = surchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE_RATE);
62	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
63	  const loyaltyDiscount =
64	    yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
65	  return Math.ceil(
66	    policyBase +
67	      curseSurcharge +
68	      enchantmentSurcharge +
69	      firstInsuranceSurcharge -
70	      loyaltyDiscount +
71	      PROCESSING_FEE_G,
72	  );
73	};
74	
75	export const processScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
76	  const results = scenario.steps.map((step) => ({
77	    premium: quotePremium(step.items, scenario.customer.yearsWithMHPCO),
78	  }));
79	  return { results };
80	};
