const isLoyalCustomer = (customer: Customer): boolean =>
  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;

const quotePremium = (items: Item[], customer: Customer): number => {
  const componentBase = COMPONENT_TYPES.reduce((sum, type) => {
    const count = items.filter((i) => i.type === type).length;
    return sum + priceForComponentGroup(count, BASE_PREMIUMS[type]);
  }, 0);
  const otherItemsBase = items
    .filter((i) => !isComponent(i))
    .reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
  const policyBase = otherItemsBase + componentBase;
  const curseSurcharge = surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
  const enchantmentSurcharge = surchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE_RATE);
  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
  const loyaltyDiscount = isLoyalCustomer(customer) ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
  return Math.ceil(
    policyBase +
      curseSurcharge +
      enchantmentSurcharge +
      firstInsuranceSurcharge -
      loyaltyDiscount +
      PROCESSING_FEE_G,
  );
};

export const processScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
  const results = scenario.steps.map((step) => ({
    premium: quotePremium(step.items, scenario.customer),
  }));
  return { results };
};
